### ✅ **Final jQuery Code (script.js):**

```javascript
$(document).ready(function () {
    $('#inputText').on('input', function () {
        const $input = $(this);
        const currentVal = $input.val();

        // Only allow uppercase letters and numbers
        const cleaned = currentVal.replace(/[^A-Z0-9]/g, '');

        // Limit to 5 characters
        const trimmed = cleaned.toUpperCase().substring(0, 5);

        // Preserve cursor position
        const cursorPos = $input[0].selectionStart;

        // Update the value
        $input.val(trimmed);

        // Restore the cursor position
        $input[0].setSelectionRange(cursorPos, cursorPos);
    });
});
```

