import software.amazon.awssdk.services.ses.model.SendEmailRequest;
import software.amazon.awssdk.services.ses.model.SendEmailResponse;
import software.amazon.awssdk.services.ses.model.EmailAddress;

public class SesEmailSender {

    public static void main(String[] args) {
        // Replace these with your actual values
        String fromEmail = "your-email@example.com";
        String toEmail = "recipient@example.com";
        String subject = "Test Email from AWS SES";
        String bodyText = "This is a test email sent using Amazon SES from Java.";

        // Initialize the SES client
        SesClient sesClient = SesClient.builder()
                .region(Region.US_EAST_1) // Choose your region
                .credentialsProvider(ProfileCredentialsProvider.create())
